// app/api/user/update/route.ts
import { NextRequest, NextResponse } from "next/server";

const BACKEND_URL = process.env.BACKEND_URL || "https://api-dev.dotportion.com";

export async function POST(request: NextRequest) {
  try {
    const token = request.cookies.get("auth-token")?.value;

    if (!token) {
      return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
    }

    const body = await request.json();

    const response = await fetch(`${BACKEND_URL}/users/update`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify(body),
    });

    const data = await response.json();

    if (!response.ok) {
      return NextResponse.json(
        { error: data.message || "Failed to update user" },
        { status: response.status }
      );
    }

    return NextResponse.json(data);
  } catch (error) {
    console.error("Update user API route error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";

export async function GET(request: NextRequest) {
  const token = request.cookies.get("auth-token")?.value;

  if (!token) {
    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
  }

  // Sync access status with backend
  const meRes = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/users/me`, {
    headers: { Authorization: `Bearer ${token}` },
  });

  const meData = await meRes.json();

  const res = NextResponse.json(meData);

  if (meData.access?.status) {
    res.cookies.set("auth-access-status", meData.access.status, {
      httpOnly: false,
      sameSite: "strict",
      secure: process.env.NODE_ENV === "production",
      path: "/",
    });
  }

  return res;
}

"use client";

import { useEffect } from "react";
import { useRouter } from "next/navigation";

export default function PendingAccessPage() {
  const router = useRouter();

  useEffect(() => {
    async function syncStatus() {
      const res = await fetch("/api/access/request-pending", {
        credentials: "include",
      });

      if (!res.ok) return;

      const data = await res.json();

      if (data.access?.status === "approved") {
        router.push("/dashboard");
      }

      if (data.access?.status === "rejected") {
        router.push("/request-access/rejected");
      }
    }

    syncStatus();
  }, [router]);

  return (
    <div className="flex flex-col items-center justify-center h-screen px-6 text-center">
      <h1 className="text-3xl font-semibold mb-4">Access Requested</h1>

      <p className="text-neutral-600 max-w-md">
        Your access request has been received. Once approved, you will be
        notified and automatically gain access to your workspace.
      </p>
    </div>
  );
}

