"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";

export default function RequestAccessPage() {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleRequestAccess = async () => {
    try {
      setLoading(true);
      setError("");

      const response = await fetch("/api/access/request", {
        method: "POST",
        credentials: "include",
      });

      const data = await response.json();

      if (!response.ok) {
        setError(data.error || "Something went wrong");
        setLoading(false);
        return;
      }

      // redirect to pending page
      router.push("/request-access/pending");
    } catch {
      setError("Failed to request access");
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-screen px-6 text-center">
      <h1 className="text-3xl font-semibold mb-4">Request Access</h1>

      <p className="text-neutral-600 max-w-md mb-8">
        You’ve completed onboarding. To start using DotPortion, you need to
        request access to your workspace. Our team will review and approve it.
      </p>

      {error && <p className="text-red-600 text-sm mb-4">{error}</p>}

      <Button
        className="px-6 py-2 text-base bg-neutral-800 hover:bg-neutral-700"
        disabled={loading}
        onClick={handleRequestAccess}
      >
        {loading ? "Requesting..." : "Request Access"}
      </Button>
    </div>
  );
}

// app/api/user/update-theme/route.ts
import { NextRequest, NextResponse } from "next/server";

const BACKEND_URL = process.env.BACKEND_URL || "https://api-dev.dotportion.com";

export async function POST(request: NextRequest) {
  try {
    const token = request.cookies.get("auth-token")?.value;

    if (!token) {
      return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
    }

    const body = await request.json();

    const response = await fetch(`${BACKEND_URL}/users/update-theme`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify(body),
    });

    const data = await response.json();

    if (!response.ok) {
      return NextResponse.json(
        { error: data.message || "Failed to update theme" },
        { status: response.status }
      );
    }

    return NextResponse.json(data);
  } catch (error) {
    console.error("Update theme API route error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

