import type React from "react";
import { useAppSelector } from "@/lib/redux/hooks";

interface ProtectedRouteProps {
  children: React.ReactNode;
}

export default function ProtectedRoute({ children }: ProtectedRouteProps) {
  // Simply check Redux state - middleware handles actual protection
  const { isAuthenticated } = useAppSelector((state) => state.auth);

  // Middleware already protects routes server-side, so if we reach here,
  // we can safely render. Just ensure Redux state is consistent.
  if (!isAuthenticated) {
    // This shouldn't happen if middleware is working, but provide fallback
    return null;
  }

  return <>{children}</>;
}

// app/api/user/update-profile/route.ts
import { NextRequest, NextResponse } from "next/server";

const BACKEND_URL = process.env.BACKEND_URL || "https://api-dev.dotportion.com";

export async function POST(request: NextRequest) {
  try {
    const token = request.cookies.get("auth-token")?.value;

    if (!token) {
      return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
    }

    const body = await request.json();

    const response = await fetch(`${BACKEND_URL}/users/update`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify(body),
    });

    const data = await response.json();

    if (!response.ok) {
      return NextResponse.json(
        { error: data.message || "Failed to update profile" },
        { status: response.status }
      );
    }

    return NextResponse.json(data);
  } catch (error) {
    console.error("Update profile API route error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

