"use client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  ChartConfig,
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
} from "@/components/ui/chart";
import { Bar, BarChart, CartesianGrid, XAxis } from "recharts";

export function TopWorkflowsChart({
  data,
}: {
  data: { name: string; calls: number }[];
}) {
  const chartConfig: ChartConfig = {
    calls: { label: "API Calls", color: "var(--chart-2)" },
  };

  const hasData =
    Array.isArray(data) && data.length > 0 && data.some((d) => d.calls > 0);

  return (
    <Card className="shadow-none border border-neutral-300 py-4">
      <CardHeader className="pb-2 px-4">
        <CardTitle className="flex items-center gap-2 font-inter text-sm font-medium">
          Top Workflows
        </CardTitle>
      </CardHeader>
      <CardContent className="px-4">
        {hasData ? (
          <ChartContainer config={chartConfig} className="w-full h-[300px]">
            <BarChart data={data}>
              <CartesianGrid vertical={false} />
              <XAxis
                dataKey="name"
                tickLine={false}
                axisLine={false}
                tickMargin={2}
              />
              <ChartTooltip
                cursor={false}
                content={<ChartTooltipContent hideLabel />}
              />
              <Bar dataKey="calls" fill="var(--chart-2)" radius={8} />
            </BarChart>
          </ChartContainer>
        ) : (
          <div className="flex items-center justify-center h-48 text-gray-400">
            No data available
          </div>
        )}
      </CardContent>
    </Card>
  );
}

"use client";

import { useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";

export default function UsernamePage() {
  const [username, setUsername] = useState("");
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const params = useSearchParams();

  const email = params.get("email");

  const submit = async () => {
    if (!username.trim()) {
      alert("Please choose a valid username.");
      return;
    }

    setLoading(true);
    const res = await fetch("/api/auth/set-username", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ email, username }),
    });

    if (!res.ok) {
      alert("Failed: " + (await res.text()));
      return;
    }

    router.push("/onboarding?step=0");
  };

  return (
    <div className="flex-1 flex flex-col justify-center w-[330px] sm:w-[384px]">
      <div className="mb-10">
        <h1 className="mt-8 mb-2 lg:text-3xl">Choose a username</h1>
      </div>
      <Label className="transition-all duration-500 ease-in-out flex flex-row gap-2 justify-between mb-2">
        <p className="text font-normal peer-disabled:cursor-not-allowed peer-disabled:opacity-70 text-sm transition-colors text-foreground flex gap-2 items-center break-all leading-normal">
          Username
        </p>
      </Label>
      <Input
        value={username}
        onChange={(e) => setUsername(e.target.value)}
        placeholder="Enter username"
        className="flex w-full shadow-none bg-neutral-100 rounded-md border border-neutral-300 text-sm leading-4 px-3 py-2 my-2 h-[34px]"
      />
      <Button
        onClick={submit}
        disabled={loading}
        className="relative cursor-pointer mt-2 space-x-2 text-center ease-out duration-200 rounded-md outline
